// This code is for n8n's "Code" node to extract and clean title and content from AI Agent output
const items = $input.all();
const results = [];

for (const item of items) {
  if (item.json && item.json.output) {
    const output = item.json.output;

    // Split into lines and remove empty ones
    const lines = output.split('\n').filter(line => line.trim() !== "");

    // Extract and clean title
    let title = lines.length > 0 ? lines[0].trim() : "";

    // Remove markdown characters like #, *, _, etc. from title
    title = title.replace(/^#+\s*/, "");     // Remove leading # and spaces
    title = title.replace(/^\*+\s*/, "");    // Remove leading * and spaces
    title = title.replace(/^\*+(.*?)\*+$/, "$1"); // Remove surrounding ** or * from both ends
    title = title.replace(/^_+(.*?)_+$/, "$1");   // Remove surrounding __ or _ from both ends

    // Extract content
    const content = lines.slice(1).join('\n').trim();

    results.push({
      json: {
        title: title,
        content: content
      }
    });
  } else {
    results.push(item);
  }
}

return results;
